class Solution:
    def strWithout3a3b(self, a: int, b: int) -> str:
        res = []
        while a or b:
            if a > b:
                if a - b > 1:
                    res.append('aa')
                    a -= 2
                else:
                    res.append('a')
                    a -= 1
            else:
                if b - a > 1:
                    res.append('bb')
                    b -= 2
                else:
                    res.append('b')
                    b -= 1
            if a and b:
                if res[-1] == 'a' or res[-1] == 'aa':
                    res.append('b')
                    b -= 1
                else:
                    res.append('a')
                    a -= 1
        return ''.join(res)
